import java.util.Scanner;

public class SecureBufferExample {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter a string: ");
        String userInput = scanner.nextLine();

        // Check if user input exceeds a safe length
        if (userInput.length() > 10) {
            System.out.println("Input exceeds maximum allowed length.");
            return;
        }

        // Allocate memory dynamically based on user input length
        char[] buffer = new char[userInput.length()];

        // Copy user input to buffer
        userInput.getChars(0, userInput.length(), buffer, 0);

        System.out.println("Input copied to buffer successfully.");
    }
}

### Explanation:
취약유형: Buffer Overflow
